// Check if there are more pages
const resp = $input.first().json;
const meta = resp.meta || {};
const lastPage = meta.last_page || 1;
const currentPage = meta.current_page || 1;

if (lastPage > 1) {
  // Output page URLs for pages 2..lastPage
  const pages = [];
  for (let p = 2; p <= Math.min(lastPage, 20); p++) {
    pages.push({ json: { page: p } });
  }
  return pages;
}

// No more pages
return [{ json: { page: 0, no_more: true } }];

// Merge page 1 + additional pages into one flat ads array
const page1Data = $('Fetch Ads Page 1').first().json;
const page1Ads = page1Data.data || [];

// Collect additional pages (if any)
let extraAds = [];
try {
  const nextPages = $('Fetch Next Pages').all();
  for (const item of nextPages) {
    const d = item.json.data || [];
    extraAds.push(...d);
  }
} catch (e) {
  // No additional pages fetched
}

const allAds = [...page1Ads, ...extraAds];

// Extract unique campaigns and groups
const campaignsMap = {};
const groupsMap = {};

for (const ad of allAds) {
  if (ad.campaign_id && !campaignsMap[ad.campaign_id]) {
    campaignsMap[ad.campaign_id] = {
      campaign_id: ad.campaign_id,
      name: ad.campaign_name || 'Campaign ' + ad.campaign_id,
      campaign_type_id: ad.campaign_type_id || null
    };
  }
  if (ad.ad_group_id && !groupsMap[ad.ad_group_id]) {
    groupsMap[ad.ad_group_id] = {
      ad_group_id: ad.ad_group_id,
      campaign_id: ad.campaign_id,
      name: ad.group_ad_name || 'Group ' + ad.ad_group_id
    };
  }
}

return [{
  json: {
    ads: allAds,
    campaigns: Object.values(campaignsMap),
    groups: Object.values(groupsMap),
    total_fetched: allAds.length
  }
}];

const data = $input.first().json;
const campaigns = data.campaigns || [];
const groups = data.groups || [];
const ads = data.ads || [];

if (ads.length === 0) {
  return [{ json: { sql: "SELECT 'no_ads' as result", stats: { ads: 0, campaigns: 0, groups: 0 } } }];
}

const esc = (s) => (s || '').replace(/'/g, "''");
const fixUrl = (u) => u ? (u.startsWith('//') ? 'https:' + u : u) : null;

const GEOZO_STATUS = {
  1: 'processed', 2: 'moderation', 3: 'banned',
  4: 'stopped', 5: 'started', 41: 'budget_ended', 42: 'suspended'
};

const campaignSqls = campaigns.map(c => {
  return `INSERT INTO campaigns (campaign_id, name, campaign_type_id, synced_at)
    VALUES (${c.campaign_id}, '${esc(c.name)}', ${c.campaign_type_id || 'NULL'}, NOW())
    ON CONFLICT (campaign_id) DO UPDATE SET
      name = EXCLUDED.name,
      campaign_type_id = COALESCE(EXCLUDED.campaign_type_id, campaigns.campaign_type_id),
      synced_at = NOW()`;
});

const groupSqls = groups.map(g => {
  return `INSERT INTO ad_groups (ad_group_id, campaign_id, name, synced_at)
    VALUES (${g.ad_group_id}, ${g.campaign_id}, '${esc(g.name)}', NOW())
    ON CONFLICT (ad_group_id) DO UPDATE SET
      campaign_id = EXCLUDED.campaign_id,
      name = EXCLUDED.name,
      synced_at = NOW()`;
});

const adSqls = ads.filter(a => a.id).map(a => {
  const title = esc(a.title);
  const url = esc(a.url || a.original_url || '');
  const shortDesc = esc(a.short_description);
  const statusId = a.status_id || null;
  const status = GEOZO_STATUS[statusId] || 'unknown';
  const banReason = a.ban ? esc(typeof a.ban === 'string' ? a.ban : JSON.stringify(a.ban)) : null;
  const adRating = a.ad_rating?.name || null;
  const geozoCreatedAt = a.created_at || null;

  // Extract bid + country_code + geo_id from nested bids structure
  let bid = null;
  let countryCode = null;
  let geoId = null;
  if (a.bids && Array.isArray(a.bids)) {
    const findGeo = (obj) => {
      if (obj.type === 'countries' && obj.bid) {
        return { bid: parseFloat(obj.bid), countryCode: obj.id, geoId: obj.geo_id };
      }
      if (obj.children) {
        for (const child of Object.values(obj.children)) {
          const r = findGeo(child);
          if (r) return r;
        }
      }
      return null;
    };
    for (const b of a.bids) {
      const r = findGeo(b);
      if (r) {
        bid = r.bid;
        countryCode = r.countryCode;
        geoId = r.geoId;
        break;
      }
    }
  }

  // Image URLs - fix protocol-relative URLs
  const imgSquare = fixUrl(a.media_contents?.['1:1']?.url || a.media_contents?.original_square?.url);
  const imgHoriz = fixUrl(a.media_contents?.['16:9']?.url || a.media_contents?.original_horizontal_16x9?.url);

  // Statistics from API (cumulative lifetime stats)
  const st = a.statistic || {};
  const totalShows = st.shows_count || 0;
  const totalClicks = st.clicks_count || 0;
  const totalMoney = st.money || 0;
  const totalCpc = st.cpc || 0;
  const totalCtr = st.confirmed_ctr || 0;
  const totalRoi = st.roi_percentage || 0;
  const totalLeads = st.postbacks_total_count || 0;
  const totalLeadsMoney = st.postbacks_confirmed_money || 0;
  const totalCr = st.cr || 0;

  return `INSERT INTO teasers (ad_id, ad_group_id, campaign_id, title, original_url, short_description, geozo_status_id, status, bid, country_code, geo_id, image_square_path, image_horizontal_path, ban_reason, ad_rating, geozo_created_at, total_shows, total_clicks, total_money, total_cpc, total_ctr, total_roi, total_leads, total_leads_confirmed_money, total_cr, total_spend_lifetime, updated_at)
    VALUES (
      ${a.id},
      ${a.ad_group_id || 'NULL'},
      ${a.campaign_id || 'NULL'},
      '${title}',
      '${url}',
      ${shortDesc ? "'" + shortDesc + "'" : 'NULL'},
      ${statusId || 'NULL'},
      '${status}',
      ${bid || 'NULL'},
      ${countryCode ? "'" + countryCode + "'" : 'NULL'},
      ${geoId || 'NULL'},
      ${imgSquare ? "'" + esc(imgSquare) + "'" : 'NULL'},
      ${imgHoriz ? "'" + esc(imgHoriz) + "'" : 'NULL'},
      ${banReason ? "'" + banReason + "'" : 'NULL'},
      ${adRating ? "'" + adRating + "'" : 'NULL'},
      ${geozoCreatedAt ? "'" + geozoCreatedAt + "'" : 'NULL'},
      ${totalShows},
      ${totalClicks},
      ${totalMoney},
      ${totalCpc},
      ${totalCtr},
      ${totalRoi},
      ${totalLeads},
      ${totalLeadsMoney},
      ${totalCr},
      ${totalMoney},
      NOW()
    )
    ON CONFLICT (ad_id) WHERE ad_id IS NOT NULL DO UPDATE SET
      ad_group_id = EXCLUDED.ad_group_id,
      campaign_id = EXCLUDED.campaign_id,
      title = EXCLUDED.title,
      original_url = EXCLUDED.original_url,
      short_description = EXCLUDED.short_description,
      geozo_status_id = EXCLUDED.geozo_status_id,
      status = EXCLUDED.status,
      bid = COALESCE(EXCLUDED.bid, teasers.bid),
      country_code = COALESCE(EXCLUDED.country_code, teasers.country_code),
      geo_id = COALESCE(EXCLUDED.geo_id, teasers.geo_id),
      image_square_path = COALESCE(EXCLUDED.image_square_path, teasers.image_square_path),
      image_horizontal_path = COALESCE(EXCLUDED.image_horizontal_path, teasers.image_horizontal_path),
      ban_reason = EXCLUDED.ban_reason,
      ad_rating = COALESCE(EXCLUDED.ad_rating, teasers.ad_rating),
      geozo_created_at = COALESCE(EXCLUDED.geozo_created_at, teasers.geozo_created_at),
      total_shows = EXCLUDED.total_shows,
      total_clicks = EXCLUDED.total_clicks,
      total_money = EXCLUDED.total_money,
      total_cpc = EXCLUDED.total_cpc,
      total_ctr = EXCLUDED.total_ctr,
      total_roi = EXCLUDED.total_roi,
      total_leads = EXCLUDED.total_leads,
      total_leads_confirmed_money = EXCLUDED.total_leads_confirmed_money,
      total_cr = EXCLUDED.total_cr,
      total_spend_lifetime = EXCLUDED.total_spend_lifetime,
      updated_at = NOW()`;
});

const allSql = [...campaignSqls, ...groupSqls, ...adSqls];

allSql.push(`UPDATE ad_groups ag SET
  ad_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id),
  ad_started_count = (SELECT COUNT(*) FROM teasers t WHERE t.ad_group_id = ag.ad_group_id AND t.geozo_status_id = 5)`);

const sql = allSql.join(';\n') + ";\nSELECT 'ok' as result, " + ads.length + " as ads_synced, " + campaigns.length + " as campaigns_synced, " + groups.length + " as groups_synced";

return [{ json: { sql, stats: { ads: ads.length, campaigns: campaigns.length, groups: groups.length } } }];
